<?php
namespace App\Notifications;use Illuminate\Bus\Queueable;use Illuminate\Notifications\Messages\MailMessage;use Illuminate\Notifications\Notification;
class MissingDailyReportNotification extends Notification{use Queueable;public function __construct(public mixed $subject=null){}public function via(object $notifiable):array{return ['mail','database'];}public function toMail(object $notifiable):MailMessage{return (new MailMessage)->subject('MissingDailyReportNotification')->line('A WorkProof accountability update requires your attention.');}public function toArray(object $notifiable):array{return ['type'=>'MissingDailyReportNotification','subject_id'=>$this->subject?->id];}}
